"use strict";(self.webpackChunkdocusaurus_knowledge_base=self.webpackChunkdocusaurus_knowledge_base||[]).push([[75093],{89077(e,t,i){i.r(t),i.d(t,{assets:()=>c,contentTitle:()=>r,default:()=>u,frontMatter:()=>a,metadata:()=>n,toc:()=>d});let n=JSON.parse('{"id":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 41 Agriculture/subsequent-expenditure-on-biological-9da09e016f","title":"Subsequent Expenditure on Biological Assets (IAS 41)","description":"September 2019","source":"@site/knowledge/6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 41 Agriculture/Subsequent Expenditure on Biological Assets (IAS 41).md","sourceDirName":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 41 Agriculture","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-41-agriculture-c896891f3d/subsequent-expenditure-on-biological-9da09e016f","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-41-agriculture-c896891f3d/subsequent-expenditure-on-biological-9da09e016f","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":1,"frontMatter":{"id":"subsequent-expenditure-on-biological-9da09e016f","title":"Subsequent Expenditure on Biological Assets (IAS 41)","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-41-agriculture-c896891f3d/subsequent-expenditure-on-biological-9da09e016f","sidebar_position":1},"sidebar":"knowledgeSidebar","previous":{"title":"Holdings of Cryptocurrencies","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-38-intangible-assets-and-ias-2-i-babc46cedc/holdings-of-cryptocurrencies-d65a896f52"},"next":{"title":"Demand Deposits with Restrictions on Use arising from a Contract with a Third Party (IAS 7)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-7-statement-of-cash-flows-5c8f1f3849/demand-deposits-with-restrictions-on-d9379cfc70"}}');var s=i(74848),o=i(28453);let a={id:"subsequent-expenditure-on-biological-9da09e016f",title:"Subsequent Expenditure on Biological Assets (IAS 41)",slug:"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-41-agriculture-c896891f3d/subsequent-expenditure-on-biological-9da09e016f",sidebar_position:1},r="Subsequent Expenditure on Biological Assets (IAS 41)",c={},d=[];function l(e){let t={h1:"h1",header:"header",p:"p",...(0,o.R)(),...e.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(t.header,{children:(0,s.jsx)(t.h1,{id:"subsequent-expenditure-on-biological-assets-ias-41",children:"Subsequent Expenditure on Biological Assets (IAS 41)"})}),"\n",(0,s.jsx)(t.p,{children:"September 2019"}),"\n",(0,s.jsx)(t.p,{children:"The Committee received a request about the accounting for costs related to the biological transformation (subsequent expenditure) of biological assets measured at fair value less costs to sell applying IAS 41. The request asked whether an entity capitalises subsequent expenditure (ie adds it to the carrying amount of the asset) or, instead, recognises subsequent expenditure as an expense when incurred."}),"\n",(0,s.jsx)(t.p,{children:"IAS 41 does not specify the accounting for subsequent expenditure for biological assets measured at fair value less costs to sell. Paragraph B62 of the Basis for Conclusions on IAS 41 explains that \u2018\u2026the [IASC] Board decided not to explicitly prescribe the accounting for subsequent expenditure related to biological assets in the Standard, because it believes to do so is unnecessary with a fair value measurement approach\u2019."}),"\n",(0,s.jsx)(t.p,{children:"Accordingly, the Committee concluded that, applying IAS 41, an entity either capitalises subsequent expenditure or recognises it as an expense when incurred. The Committee observed that capitalising subsequent expenditure or recognising it as an expense has no effect on the fair value measurement of biological assets nor does it have any effect on profit or loss; however, it affects the presentation of amounts in the statement of profit or loss. In assessing how to present such subsequent expenditure in the statement of profit or loss, an entity would apply the requirements in paragraphs 81\u2013105 of IAS 1 Presentation of Financial Statements. In particular, the Committee observed that the entity would:"}),"\n",(0,s.jsx)(t.p,{children:"a. applying paragraph 85, \u2018present additional line items (including by disaggregating the line items listed in paragraph 82), headings and subtotals in the statement(s) presenting profit or loss and other comprehensive income when such presentation is relevant to an understanding of the entity\u2019s financial performance\u2019; and\nb. applying paragraph 99, present in the statement(s) presenting profit or loss and other comprehensive income or in the notes an analysis of expenses recognised in profit or loss using a classification based on either their nature or their function within the entity, whichever provides information that is reliable and more relevant."}),"\n",(0,s.jsx)(t.p,{children:"Applying paragraph 13 of IAS 8 Accounting Policies, Changes in Accounting Estimates and Errors, an entity would apply its accounting policy for subsequent expenditure consistently to each group of biological assets. An entity would also disclose the selected accounting policy applying paragraphs 117\u2013124 of IAS 1 if that disclosure would assist users of financial statements in understanding how those transactions are reflected in reported financial performance."}),"\n",(0,s.jsx)(t.p,{children:"In the light of its analysis, the Committee considered whether to add a project to its standard-setting agenda on the accounting for subsequent expenditure on biological assets. The Committee has not obtained evidence to suggest that standard-setting on this matter at this time would result in an improvement to financial reporting that would be sufficient to outweigh the costs. The Committee therefore decided not to add the matter to its standard-setting agenda."})]})}function u(e={}){let{wrapper:t}={...(0,o.R)(),...e.components};return t?(0,s.jsx)(t,{...e,children:(0,s.jsx)(l,{...e})}):l(e)}},28453(e,t,i){i.d(t,{R:()=>a,x:()=>r});var n=i(96540);let s={},o=n.createContext(s);function a(e){let t=n.useContext(o);return n.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(s):e.components||s:a(e.components),n.createElement(o.Provider,{value:t},e.children)}}}]);